bash_commands.command:
python3 << 'EOF'
import os
try:
    os.makedirs('/workspace', exist_ok=True)
    print("Created /workspace")
except PermissionError:
    print("Permission denied for /workspace")
    # Try a workaround
    if os.getuid() == 0:
        print("Running as root")
    else:
        print(f"Running as UID {os.getuid()}")
EOF

